frappe.web_form.after_load = function () {

    // Get flight from URL
    const params = new URLSearchParams(window.location.search);
    const flight_name = params.get("flight");

    if (!flight_name) return;

    // Set flight field
    frappe.web_form.set_value("flight", flight_name);

    // Fetch flight details
    frappe.call({
        method: "frappe.client.get",
        args: {
            doctype: "Airplane Flight",
            name: flight_name
        },
        callback: function (r) {
            if (r.message) {

                let duration_seconds = r.message.duration || 0;

                // Convert seconds to minutes
                let minutes = duration_seconds / 60;

                // ₹3 per minute
                let price = minutes * 50;

                // Set price
                frappe.web_form.set_value("flight_price", price);

                // Make read-only
                frappe.web_form.set_df_property("flight_price", "read_only", 1);
            }
        }
    });
};
